parameters.jsCode:
// Get jobs array from Firecrawl JSON output
// Firecrawl v2 returns structured data under: data.json.jobs
const jobs = $json?.data?.json?.jobs || [];

let text = '';
let i = 1;

// Loop through each job and build a single text block
for (const j of jobs) {
  const title = (j.title || '').trim();
  const url = (j.url || '').trim();
  const location = (j.location || '').trim();
  const publishedDate = (j.publishedDate || '').trim();

  // Skip invalid jobs (must have at least title and url)
  if (!title || !url) continue;

  // Append job data in a readable multi-line format
  text +=
`job_${i}
${title}
${url}
${location}
${publishedDate}

`;
  i++;
}

// Fallback: if no jobs were extracted, store the career page URL instead
if (!text.trim()) {
  text = $('Search records').item.json['Career Page Link'] || '';
}

// Return ONLY ONE item so Google Sheets updates a single cell
return [
  {
    json: {
      SaveJob: text.trim(),   // All jobs combined into one string
      jobCount: i - 1         // Total number of valid jobs found
    }
  }
];

// All job items from the actor/HTTP node
const items = $input.all();
const jobs = items.map(i => i.json);

// ✅ Pull the current loop item (the company row) using $item(0)
// This returns the data of the current execution item flowing through the loop
const loop = $item(0).$node["Loop Over Items1"].json;

// ✅ Use the exact key name from your sheet: "Linkedin Page Link"
const linkedInPageLink = loop["Company Linkedin  URL"] || "";

// ✅ Company name will be taken from loop, otherwise from the job node's company.name
const companyName =
  loop["Company Name"] ||
  items?.[0]?.json?.company?.name ||
  "";

const rowNumber = loop["id"] ?? null;

let text = '';
let i = 1;

for (const j of jobs) {
  const title = (j.title || '').trim();
  const url = (j.linkedinUrl || j.linkedInUrl || '').trim();

  // location handling (sometimes object)
  let location = '';
  if (typeof j.location === 'string') location = j.location.trim();
  else if (j.location?.linkedinText) location = String(j.location.linkedinText).trim();
  else location = (j.headerCaptionText || '').split('·')[0].trim();

  const publishedDate = (j.postedDate || '').split('T')[0];

  if (!title || !url) continue;

  text += `job_${i}\n${title}\n${url}\n${location}\n${publishedDate}\n\n`;
  i++;
}

if (!text.trim()) text = 'No LinkedIn jobs found';

// ✅ Return ONE item but KEEP loop fields
return [{
  json: {
    row_number: rowNumber,
    "Company Name": companyName,
    "Company Linkedin  URL": linkedInPageLink,
    SaveJob: text.trim(),
    jobCount: i - 1,
    source: "linkedin"
  }
}];

